37	
38	    it("should apply cursed item surcharge (50%)", () => {
39	      expect(createQuote([{ type: "sword", damage: 50, cursed: true }])).toBe(160);
40	    });
41	    it("should apply enchanted item surcharge (level 5) to sword", () => {
42	      expect(createQuote([{ type: "sword", damage: 50, enchantment: 5 }])).toBe(131);
43	    });
44	    it("should apply high enchantment surcharge (level 5+, 30%)", () => {
45	      expect(createQuote([{ type: "sword", damage: 50, enchantment: 5 }])).toBe(130);
46	    });
47	    it("should apply cursed surcharge and enchanted surcharge together", () => {
48	      expect(createQuote([{ type: "sword", damage: 50, cursed: true, enchantment: 5 }])).toBe(185);
