54	    it("should apply first insurance surcharge (10%) when isFirstInsurance is true", () => {
55	      expect(createQuote([{ type: "sword", damage: 50 }], { isFirstInsurance: true })).toBe(116);
56	    });
57	    it("should apply follow-up contract discount (-15%) when isFollowUpContract is true", () => {
58	      expect(createQuote([{ type: "sword", damage: 50 }], { isFollowUpContract: true })).toBe(89);
59	    });
60	
61	    it("should round premium up to nearest gold in MHPCO's favor", () => {
62	      expect(createQuote([{ type: "staff", damage: 50 }], { isFirstInsurance: true })).toBe(95);
63	    });
64	
65	    it("should reject unknown item type with error", () => {
66	      expect(() => createQuote([{ type: "unknown", damage: 50 }])).toThrow("Unknown item type: unknown");
67	    });
68	    it.todo("should reject negative damage amount with error");
69	  });
