71	  // Claim Operations - Base Functionality
72	  describe("Claim Operations", () => {
73	    it("should process claim for single item with damage below deductible", () => {
74	      const policy = { items: [{ type: "sword", damage: 50 }], coverage: 100 };
75	      const damage = { type: "sword", amount: 50 };
76	      expect(processClaim(policy, damage)).toBe(0);
