78	    it("should return payout minus deductible when damage exceeds deductible", () => {
79	      const policy = { items: [{ type: "sword", damage: 50 }], coverage: 100 };
80	      const damage = { type: "sword", amount: 150 };
81	      expect(processClaim(policy, damage)).toBe(50);
82	    });
83	
84	    it.todo("should subtract 100G deductible from damage");
85	
86	    it("should cap payout at 2x insurance value", () => {
87	      const policy = { items: [{ type: "sword", damage: 50 }], coverage: 100 };
88	      const damage = { type: "sword", amount: 350 };
89	      expect(processClaim(policy, damage)).toBe(200);
