91	
92	    it("should reimburse high enchantment damage at 50%", () => {
93	      const policy = { items: [{ type: "sword", damage: 50, enchantment: 8 }], coverage: 100 };
94	      const damage = { type: "sword", amount: 250 };
95	      expect(processClaim(policy, damage)).toBe(300);
