97	    it("should apply dragon material full reimbursement", () => {
98	      const policy = { items: [{ type: "sword", damage: 50, dragonMaterial: true }], coverage: 100 };
99	      const damage = { type: "sword", amount: 150 };
100	      expect(processClaim(policy, damage)).toBe(150);
101	    });
102	
103	    it("should process multiple damage events to same item type with separate deductibles", () => {
104	      const policy = { items: [{ type: "sword", damage: 50 }], coverage: 100 };
105	      const damages = [
106	        { type: "sword", amount: 130 },
107	        { type: "sword", amount: 130 }
108	      ];
109	      const result = processMultipleDamages(policy, damages);
110	      expect(result).toBe(60); // (130-100) + (130-100) = 30 + 30 = 60
111	    });
112	    it.todo("should apply separate deductible for each damage event");
113	
114	    it("should reject claim for damage to item not in policy", () => {
115	      const policy = { items: [{ type: "sword", damage: 50 }], coverage: 100 };
116	      const damage = { type: "amulet", amount: 150 };
117	      expect(() => processClaim(policy, damage)).toThrow();
118	    });
119	    it("should reject claim with negative damage amount", () => {
120	      const policy = { items: [{ type: "sword", damage: 50 }], coverage: 100 };
121	      const damage = { type: "sword", amount: -50 };
122	      expect(() => processClaim(policy, damage)).toThrow();
123	    });
124	  });
125	});
